// Generated by Selenium IDE
const { Builder, By, Key, until } = require('selenium-webdriver');
const assert = require('assert');
require('chromedriver');

describe('button search', function() {
  this.timeout(30000);
  let driver;
  let vars;
  beforeEach(async function() {
    driver = await new Builder().forBrowser('chrome').build();
    vars = {};
  });
  afterEach(async function() {
    await driver.quit();
  });
  it('button search', async function() {
    await driver.get("http://localhost:4200/admin-user/add-user");
    await driver.manage().window().setRect({ width: 1920, height: 1040 });
    assert(await driver.findElement(By.css(".ant-table-placeholder > .ant-table-cell")).getText() == "該当データがありません");
    await driver.findElement(By.name("Search")).click();
    {
      const elements = await driver.findElements(By.css(".anticon-loading > svg"));
      assert(elements.length);
    }
    {
      const elements = await driver.findElements(By.css(".ant-spin-dot-item:nth-child(3)"));
      assert(elements.length);
    }
    await driver.sleep(5000);
    await driver.findElement(By.name("Search")).click();
    await driver.findElement(By.name("Search")).click();
    await driver.findElement(By.name("Search")).click();
    await driver.findElement(By.name("Search")).click();
    await driver.findElement(By.name("Search")).click();
    await driver.findElement(By.name("Search")).click();
    await driver.findElement(By.name("Search")).click();
    await driver.findElement(By.name("Search")).click();
    await driver.findElement(By.name("Search")).click();
    await driver.findElement(By.name("Search")).click();
    await driver.findElement(By.name("Search")).click();
    {
      const elements = await driver.findElements(By.css(".anticon-loading > svg"));
      assert(elements.length);
    }
    {
      const elements = await driver.findElements(By.css(".ant-spin-dot-item:nth-child(3)"));
      assert(elements.length);
    }
  });
});
